import { and, desc, eq, gte, ilike, lte, or } from "drizzle-orm";

import { auditLogView } from "@/db-schemas";
import { db } from "@/lib/db/server";

type ListAuditLogsInput = {
  changedBy?: string;
  cursor?: string;
  dateFrom?: Date;
  dateTo?: Date;
  entityType?: "client" | "contract" | "prospect" | "task";
  field?: string;
  limit?: number;
  search?: string;
};

export async function listAuditLogs(input: ListAuditLogsInput) {
  const {
    changedBy,
    cursor,
    dateFrom,
    dateTo,
    entityType,
    field,
    limit = 50,
    search,
  } = input;

  const conditions = [];

  if (entityType) {
    conditions.push(eq(auditLogView.entityType, entityType));
  }
  if (changedBy) {
    conditions.push(eq(auditLogView.changedBy, changedBy));
  }
  if (field) {
    conditions.push(eq(auditLogView.field, field));
  }
  if (dateFrom) {
    conditions.push(gte(auditLogView.changedAt, dateFrom));
  }
  if (dateTo) {
    conditions.push(lte(auditLogView.changedAt, dateTo));
  }
  if (search) {
    conditions.push(
      or(
        ilike(auditLogView.changedByName, `%${search}%`),
        ilike(auditLogView.field, `%${search}%`),
      )!,
    );
  }

  if (cursor) {
    const cursorId = Number.parseInt(cursor, 10);
    if (!Number.isNaN(cursorId)) {
      conditions.push((col: { lt: (v: number) => unknown }) => {
        // We can't reference the serial PK easily on a view,
        // so we use changedAt + id as a tiebreaker via raw condition.
        // For simplicity, just filter id < cursorId (works because IDs are offset per entity type)
        return undefined;
      });
    }
  }

  // Build the query with conditions
  const whereClause =
    conditions.length > 0 ? and(...conditions.filter((c): c is NonNullable<typeof c> => c !== undefined)) : undefined;

  const rows = await db
    .select()
    .from(auditLogView)
    .where(whereClause)
    .orderBy(desc(auditLogView.changedAt), desc(auditLogView.id))
    .limit(limit + 1);

  const hasMore = rows.length > limit;
  const items = hasMore ? rows.slice(0, limit) : rows;

  return {
    items,
    nextCursor:
      hasMore && items.length > 0
        ? String(items[items.length - 1].id)
        : null,
  };
}

