import type { ColumnDef } from "@tanstack/react-table";
import { Calendar, FileText, List, User } from "lucide-react";

import { createColumnConfigHelper } from "@/components/data-table-filter/core/filters";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { formatRelativeTime } from "@/lib/utils";
import type { client } from "@/rpc/client";

type AuditLogListOutput = Awaited<
  ReturnType<typeof client.auditLog.list>
>;
export type AuditLogItem = AuditLogListOutput["items"][number];

const dtf = createColumnConfigHelper<AuditLogItem>();

export const auditLogColumnsConfig = [
  dtf
    .date()
    .id("changedAt")
    .accessor((row) =>
      row.changedAt ? new Date(row.changedAt) : new Date(),
    )
    .displayName("Date")
    .icon(Calendar)
    .build(),
  dtf
    .option()
    .id("entityType")
    .accessor((row) => row.entityType)
    .displayName("Entity Type")
    .icon(List)
    .build(),
  dtf
    .text()
    .id("field")
    .accessor((row) => row.field)
    .displayName("Field")
    .icon(FileText)
    .build(),
  dtf
    .text()
    .id("changedByName")
    .accessor((row) => row.changedByName ?? "")
    .displayName("Changed By")
    .icon(User)
    .build(),
] as const;

const entityTypeLabels: Record<string, string> = {
  client: "Client",
  contract: "Contract",
  prospect: "Prospect",
  task: "Task",
};

export const auditLogColumnDefs: ColumnDef<AuditLogItem>[] = [
  {
    accessorKey: "changedAt",
    cell: ({ row }) =>
      row.original.changedAt ? (
        <TooltipProvider delay={200}>
          <Tooltip>
            <TooltipTrigger className="cursor-default text-muted-foreground text-sm">
              {formatRelativeTime(row.original.changedAt)}
            </TooltipTrigger>
            <TooltipContent>
              {new Date(row.original.changedAt).toLocaleString()}
            </TooltipContent>
          </Tooltip>
        </TooltipProvider>
      ) : null,
    header: "Date",
    id: "changedAt",
  },
  {
    accessorKey: "changedByName",
    cell: ({ row }) => (
      <div className="flex items-center gap-2">
        <Avatar className="h-5 w-5">
          <AvatarImage src={row.original.changedByImage ?? undefined} />
          <AvatarFallback>
            {row.original.changedByName?.[0]?.toUpperCase() ?? "?"}
          </AvatarFallback>
        </Avatar>
        <span className="text-sm">{row.original.changedByName}</span>
      </div>
    ),
    header: "Changed By",
    id: "changedByName",
  },
  {
    accessorKey: "entityType",
    cell: ({ row }) => (
      <Badge variant="outline">
        {entityTypeLabels[row.original.entityType] ??
          row.original.entityType}
      </Badge>
    ),
    header: "Entity Type",
    id: "entityType",
  },
  {
    accessorKey: "entityId",
    cell: ({ row }) => (
      <span className="font-mono text-muted-foreground text-xs">
        #{row.original.entityId}
      </span>
    ),
    header: "Entity ID",
    id: "entityId",
  },
  {
    accessorKey: "field",
    cell: ({ row }) => (
      <span className="font-medium text-sm">{row.original.field}</span>
    ),
    header: "Field",
    id: "field",
  },
  {
    accessorKey: "oldValue",
    cell: ({ row }) =>
      row.original.oldValue ? (
        <span className="max-w-40 truncate text-muted-foreground text-sm">
          {row.original.oldValue}
        </span>
      ) : (
        <span className="text-muted-foreground text-xs">&mdash;</span>
      ),
    header: "Old Value",
    id: "oldValue",
  },
  {
    accessorKey: "newValue",
    cell: ({ row }) =>
      row.original.newValue ? (
        <span className="max-w-40 truncate text-sm">
          {row.original.newValue}
        </span>
      ) : (
        <span className="text-muted-foreground text-xs">&mdash;</span>
      ),
    header: "New Value",
    id: "newValue",
  },
];

export const entityTypeOptions = [
  { label: "Task", value: "task" },
  { label: "Client", value: "client" },
  { label: "Contract", value: "contract" },
  { label: "Prospect", value: "prospect" },
];

import { useQuery } from "@tanstack/react-query";
import { createFileRoute, useNavigate } from "@tanstack/react-router";
import { useMemo } from "react";

import type { FiltersState } from "@/components/data-table-filter/core/types";
import { DataViewLayout } from "@/components/layouts/data-view-layout";
import {
  type AuditLogItem,
  auditLogColumnDefs,
  auditLogColumnsConfig,
  entityTypeOptions,
} from "@/routes/(protected)/(app)/audit-log/-view-config";
import { rpc } from "@/rpc/client";

export const Route = createFileRoute("/(protected)/(app)/audit-log")({
  component: AuditLogPage,
});

function filtersToInput(filters: FiltersState) {
  let entityType: "client" | "contract" | "prospect" | "task" | undefined;
  let dateFrom: Date | undefined;
  let dateTo: Date | undefined;

  for (const f of filters) {
    if (f.columnId === "entityType" && f.type === "option") {
      entityType = f.values[0] as AuditLogItem["entityType"];
    }
    if (f.columnId === "changedAt" && f.type === "date") {
      if (f.operator === "gte" && f.value) dateFrom = new Date(f.value);
      if (f.operator === "lte" && f.value) dateTo = new Date(f.value);
    }
  }

  return { dateFrom, dateTo, entityType };
}

function AuditLogPage() {
  const navigate = useNavigate();

  const filterOptions = useMemo(
    () => ({
      entityType: entityTypeOptions,
    }),
    [],
  );

  return (
    <DataViewLayout<AuditLogItem>
      baseUrl="/audit-log"
      buildQueryOptions={({ filters, cursor, limit, search }) =>
        rpc.auditLog.list.queryOptions({
          input: {
            ...filtersToInput(filters),
            cursor,
            limit,
            search,
          },
        })
      }
      columnDefs={auditLogColumnDefs}
      columnsConfig={auditLogColumnsConfig}
      domain="audit_log"
      emptyMessage="No audit logs found"
      filterOptions={filterOptions}
      getRowId={(row) => `${row.entityType}-${row.id}`}
      label="Audit Log"
      onRowClick={(row) => {
        const id = row.entityId;
        switch (row.entityType) {
          case "task":
            navigate({ to: "/tasks", search: { highlight: id } });
            break;
          case "client":
            navigate({ params: { clientId: id }, to: "/clients/$clientId" });
            break;
          case "contract":
            navigate({
              params: { contractId: id },
              to: "/contracts/$contractId",
            });
            break;
          case "prospect":
            navigate({ to: "/prospects" });
            break;
        }
      }}
      searchPlaceholder="Search by user or field..."
    />
  );
}

