import { integer, pgView, text, timestamp } from "drizzle-orm/pg-core";
import { sql } from "drizzle-orm";

import { clientEvents } from "./client";
import { contractEvents } from "./client-contract";
import { prospectEvents } from "./prospect";
import { taskEvents } from "./task";
import { user } from "./auth";

export const auditLogView = pgView("audit_log").as((qb) => {
  const taskEventsSubquery = qb
    .select({
      changedAt: taskEvents.changedAt,
      changedBy: taskEvents.changedBy,
      changedByEmail: user.email,
      changedByImage: user.image,
      changedByName: user.name,
      changedByPhone: user.phoneNumber,
      entityId: taskEvents.taskId,
      entityType: sql<"task">`'task'`.as("entity_type"),
      field: taskEvents.field,
      id: taskEvents.id,
      newValue: taskEvents.newValue,
      oldValue: taskEvents.oldValue,
    })
    .from(taskEvents)
    .leftJoin(user, sql`${taskEvents.changedBy} = ${user.id}`)
    .as("te");

  return qb.select().from(taskEventsSubquery);
});

export type AuditLogEntry = typeof auditLogView.$inferSelect;

